import React from "react";
import { motion } from "framer-motion";
import UploadImage from "./UploadImage";

// Animation variants for a smooth fade-in and upward motion
const containerVariants = {
  hidden: { opacity: 0, y: 20 },
  visible: { opacity: 1, y: 0 },
};

const Header = () => (
  <motion.header
    className="text-center"
    initial="hidden"
    animate="visible"
    transition={{ duration: 0.5 }}
    variants={containerVariants}
  >
    <h1 className="text-4xl font-extrabold text-gray-900 tracking-tight">
      Radiology &amp; Oncology AI
    </h1>
    <p className="mt-2 text-lg text-gray-600">
      Upload medical images for AI-powered analysis and insights.
    </p>
  </motion.header>
);

const UploadSection = () => (
  <motion.section
    aria-labelledby="upload-section-heading"
    className="mt-6 w-full max-w-lg bg-white border border-gray-200 rounded-lg p-6 shadow-lg"
    initial="hidden"
    animate="visible"
    transition={{ duration: 0.5, delay: 0.2 }}
    variants={containerVariants}
  >
    <h2 id="upload-section-heading" className="text-xl font-semibold text-gray-800 text-center">
      Upload Medical Image
    </h2>
    <p className="mt-2 text-center text-sm text-gray-500">
      Supported formats: JPG, PNG, DICOM
    </p>
    <div className="mt-4 flex flex-col items-center">
      <UploadImage />
    </div>
  </motion.section>
);

const ReportSection = () => (
  <motion.section
    aria-labelledby="report-section-heading"
    className="mt-8 w-full max-w-3xl bg-white border border-gray-300 rounded-lg p-6 shadow-lg"
    initial="hidden"
    animate="visible"
    transition={{ duration: 0.5, delay: 0.4 }}
    variants={containerVariants}
  >
    <h2 id="report-section-heading" className="text-2xl font-bold text-gray-800 mb-4 text-center">
      AI Analysis Report
    </h2>
    <p className="text-gray-700 leading-relaxed text-center">
      The AI model has analyzed the uploaded image and detected{" "}
      <span className="font-semibold">relevant medical patterns</span>. Please review the detailed report below for potential findings. Consult a{" "}
      <span className="font-semibold">medical expert</span> for accurate interpretation.
    </p>
  </motion.section>
);

const Footer = () => (
  <motion.footer
    className="mt-8 text-center text-sm text-gray-500"
    initial="hidden"
    animate="visible"
    transition={{ duration: 0.5, delay: 0.6 }}
    variants={containerVariants}
  >
    &copy; {new Date().getFullYear()} Radiology AI. All rights reserved.
  </motion.footer>
);

function App() {
  return (
    <div className="min-h-screen bg-gray-50 flex flex-col items-center justify-center py-10 px-4">
      <Header />
      <UploadSection />
      <ReportSection />
      <Footer />
    </div>
  );
}

export default App;
